var richText7 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u898B\u5230 Buri\uFF0C\u4E00\u4F4D\u8070\u660E\u7684\u8001\u5A66\u4EBA\uFF0C\u5E36\u8457\u4E00\u6839\u5DE8\u5927\u7684\u897F\u846B\u8606\u7A7F\u904E\u68EE\u6797\u56DE\u5BB6\uFF0C\u4F46\u4E00\u96BB\u9951\u9913\u7684\u8001\u864E\u3001\u4E00\u96BB\u8CAA\u5A6A\u7684\u7345\u5B50\u548C\u4E00\u96BB\u72E1\u733E\u7684\u72D0\u72F8\u90FD\u60F3\u628A\u5979\u5403\u6389\u3002\u6191\u85C9\u8457\u9748\u5DE7\u7684\u601D\u7DAD\u548C\u4E00\u500B\u72E1\u733E\u7684\u8A08\u5283\uFF0CBuri \u4E00\u500B\u500B\u5730\u667A\u52DD\u8001\u864E\u548C\u7345\u5B50\uFF0C\u4F46\u5979\u7684\u628A\u6232\u80FD\u5426\u5C0D\u8070\u660E\u7684\u72D0\u72F8\u594F\u6548\u5462\uFF1F\u9019\u500B\u5145\u6EFF\u9A5A\u559C\u548C\u91CD\u8907\u97FB\u5F8B\u7684\u6D3B\u6F51\u6545\u4E8B\u4F7F\u5E74\u8F15\u8B80\u8005\u5728 Buri \u5B89\u5168\u56DE\u5BB6\u7684\u904E\u7A0B\u4E2D\u5FCD\u4E0D\u4F4F\u54AF\u54AF\u7B11\u3002" }), /* @__PURE__ */ e("p", { children: "\u9019\u672C\u8FF7\u4EBA\u7684\u96D9\u8A9E\u6545\u4E8B\u4F86\u81EA Mantra Lingua \u7684\u4E16\u754C\u6545\u4E8B\u7CFB\u5217\uFF0C\u5C07\u4E00\u500B\u50B3\u7D71\u7684\u5B5F\u52A0\u62C9\u6545\u4E8B\u4EE5\u751F\u52D5\u7684\u63D2\u5716\u548C\u5DE7\u5999\u7684\u8F49\u6298\u5E36\u5165\u751F\u6D3B\uFF0C\u8B93\u5B69\u5B50\u548C\u5927\u4EBA\u90FD\u611F\u5230\u6109\u6085\u3002\u975E\u5E38\u9069\u5408\u5728\u8AB2\u5802\u4E0A\u6216\u5728\u5BB6\u88E1\u5927\u8072\u5206\u4EAB\uFF0C\u9069\u5408\u63A2\u7D22\u4E16\u754C\u5404\u5730\u7684\u6C11\u9593\u6545\u4E8B\uFF0C\u8A0E\u8AD6\u52C7\u6C23\u548C\u667A\u6167\uFF0C\u4EE5\u53CA\u4E00\u8D77\u767C\u73FE\u4E00\u4E9B\u5370\u5EA6\u6587\u5316\u3002" })] });
var richText8 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u800C\u5BB6\u4FC2\u6392\u71C8\u7BC0\uFF0C\u4F46\u5C0FDeepak\u7684\u60C5\u6CC1\u5514\u4FC2\u5481\u9806\u5229\u2014\u2014\u7238\u7238\u5FD8\u8A18\u5497\u79AE\u82B1\uFF0C\u71C8\u4E32\u58DE\u5497\uFF0C\u800CDeepak\u807D\u5B8C\u62C9\u746A\u540C\u897F\u5854\u5605\u6545\u4E8B\u4E4B\u5F8C\uFF0C\u76F8\u4FE1\u60E1\u9B54\u738B\u62C9\u74E6\u7D0D\u6703\u569F\u6435\u4F62\uFF01\u7576\u4F62\u5605\u5BB6\u4EBA\u6E96\u5099\u6176\u795D\u71C8\u5149\u7BC0\uFF0CDeepak\u5605\u64D4\u5FC3\u8F49\u5316\u70BA\u5C0D\u7F8E\u5473\u4F73\u991A\u3001\u9583\u720D\u7684\u88DD\u98FE\u3001\u4EE5\u53CA\u6551\u5834\u9A5A\u559C\u7684\u8208\u596E\u3002\u52A0\u5165Deepak\uFF0C\u4E00\u9F4A\u5C55\u958B\u4E00\u5834\u5C07\u73FE\u4EE3\u5BB6\u5EAD\u8DA3\u4E8B\u540C\u6392\u71C8\u7BC0\u9B54\u6CD5\u7D50\u5408\u5605\u6709\u8DA3\u5192\u96AA\u3002" }), /* @__PURE__ */ e("p", { children: "\u4F5C\u70BAMantra Lingua\u7684\u6176\u795D\u7CFB\u5217\u4E4B\u4E00\uFF0C\u5462\u672C\u96D9\u8A9E\u66F8\u5145\u6EFF\u8272\u5F69\u8C50\u5BCC\u7684\u5716\u7247\u3001\u7C21\u55AE\u7684\u98DF\u8B5C\u548C\u6709\u8DA3\u7684\u4E8B\u5BE6\uFF0C\u5E6B\u52A9\u5BB6\u5EAD\u6DF1\u5165\u4E86\u89E3\u4F86\u81EA\u4E16\u754C\u5404\u5730\u7684\u6392\u71C8\u7BC0\u50B3\u7D71\u3002\u7121\u8AD6\u4FC2\u55BA\u5C4B\u4F01\u5B9A\u4FC2\u55BA\u5B78\u6821\uFF0C\u5462\u500B\u90FD\u4FC2\u4E00\u500B\u597D\u597D\u5605\u65B9\u6CD5\u53BB\u4ECB\u7D39\u5C0F\u670B\u53CB\u8A8D\u8B58\u5514\u540C\u6587\u5316\uFF0C\u5206\u4EAB\u7BC0\u65E5\u6545\u4E8B\uFF0C\u4E26\u5275\u9020\u6109\u5FEB\u7684\u56DE\u61B6\uFF0C\u8207\u5927\u5BB6\u4E00\u8D77\u9032\u884C\u6D3B\u52D5\u3002" })] });
var richText9 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u5C0F\u7D05\u6BCD\u96DE\u6709\u4E00\u500B\u5435\u9B27\u7684\u9130\u5C45\u2014\u2014\u72D0\u72F8\u592A\u592A\uFF0C\u7E3D\u662F\u8CAA\u5FC3\u60F3\u5403\u70E4\u96DE\uFF0C\u9084\u6709\u5979\u72E1\u733E\u7684\u5152\u5B50\u65AF\u840A\uFF0C\u6B63\u60F3\u6355\u6349\u4E00\u96BB\u3002\u4F46\u662F\u5728\u9019\u500B\u7D93\u5178\u6545\u4E8B\u7684\u6709\u8DA3\u8B8A\u9AD4\u4E2D\uFF0C\u65AF\u840A\u548C\u5C0F\u7D05\u806F\u624B\u6349\u5F04\u4ED6\u90A3\u5C08\u6A6B\u7684\u5ABD\u5ABD\uFF0C\u627E\u5230\u4E00\u500B\u8070\u660E\u7684\u65B9\u6CD5\u4F86\u9935\u990A\u72D0\u72F8\u4E00\u5BB6\uFF0C\u800C\u4E0D\u8B93\u4EFB\u4F55\u4EBA\u4E0A\u9910\u684C\u3002\u9019\u6545\u4E8B\u5145\u6EFF\u4E86\u7B11\u8072\u3001\u5718\u968A\u5408\u4F5C\u548C\u8070\u660E\u7684\u9EDE\u5B50\uFF0C\u5C55\u73FE\u4E86\u5584\u826F\u548C\u5FEB\u901F\u601D\u8003\u5982\u4F55\u62EF\u6551\u4E00\u5929\u3002" }), /* @__PURE__ */ e("p", { children: "\u9019\u500B\u4F86\u81EAMantra Lingua\u7684\u300A\u6C11\u9593\u6545\u4E8B\u3001\u795E\u8A71\u548C\u50B3\u8AAA\u300B\u7CFB\u5217\u7684\u96D9\u8A9E\u91CD\u8FF0\uFF0C\u70BA\u9019\u500B\u8001\u5B57\u865F\u5E36\u4F86\u4E86\u65B0\u9BAE\u8DA3\u5473\uFF0C\u914D\u4EE5\u751F\u52D5\u7684\u5716\u7247\u548C\u97FB\u5F8B\uFF0C\u5B69\u5B50\u5011\u548C\u5927\u4EBA\u5011\u90FD\u6703\u559C\u611B\u3002\u5C0D\u65BC\u5BB6\u5EAD\u548C\u6559\u5BA4\u4F86\u8AAA\uFF0C\u9019\u662F\u4E00\u500B\u5F88\u597D\u7684\u65B9\u5F0F\u4F86\u804A\u804A\u5584\u826F\u3001\u5408\u4F5C\u548C\u5F9E\u4E0D\u540C\u89D2\u5EA6\u770B\u4E8B\u60C5\uFF0C\u540C\u6642\u63A2\u7D22\u4F86\u81EA\u4E16\u754C\u5404\u5730\u7684\u6545\u4E8B\u3002" })] });
var richText10 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u5B78\u6821\u88E1\u6709\u500B\u5973\u5B69\u5728\u6B3A\u8CA0\u827E\u8389\uFF0C\u4F46\u5979\u628A\u9019\u4EF6\u4E8B\u85CF\u5728\u5FC3\u88E1\uFF0C\u5BEB\u4E0B\u767C\u751F\u7684\u4E8B\u5728\u5979\u7684\u65E5\u8A18\u88E1\u3002\u60C5\u6CC1\u5F9E\u58DE\u8B8A\u5F97\u66F4\u58DE\uFF0C\u76F4\u5230\u6709\u4E00\u5929\u827E\u8389\u88AB\u767C\u73FE\u5F9E\u5ABD\u5ABD\u90A3\u88E1\u5077\u9322\uFF0C\u5979\u75DB\u54ED\u6D41\u6D95\uFF0C\u5411\u7236\u6BCD\u50BE\u8A34\u4E86\u4E00\u5207\u3002\u95B1\u8B80\u827E\u8389\u7684\u65E5\u8A18\uFF0C\u770B\u770B\u5979\u662F\u5982\u4F55\u61C9\u5C0D\u6B3A\u51CC\uFF0C\u4E26\u4E14\u662F\u5982\u4F55\u5236\u6B62\u9019\u4E00\u5207\u7684\u3002" }), /* @__PURE__ */ e("p", { children: "\u827E\u8389\u7684\u79D8\u5BC6\u65E5\u8A18\u662F\u4E00\u672C\u512A\u79C0\u7684\u96D9\u8A9E\u500B\u4EBA\u3001\u793E\u6703\u548C\u5065\u5EB7\u6559\u80B2\u8CC7\u6E90\uFF0C\u9069\u5408\u7236\u6BCD\u3001\u8001\u5E2B\u3001\u793E\u5DE5\u548C\u8F14\u5C0E\u54E1\u4F7F\u7528\u3002\u8A72\u66F8\u4EE5\u7B2C\u4E00\u4EBA\u7A31\u7684\u6558\u8FF0\u65B9\u5F0F\uFF0C\u8B93\u8B80\u8005\u611F\u540C\u8EAB\u53D7\u6210\u70BA\u53D7\u5BB3\u8005\uFF0C\u5F9E\u4E8C\u7D1A\u968E\u6BB5\u8D77\u90FD\u662F\u5FC5\u8B80\u7684\u66F8\u7C4D\u3002\u66F8\u4E2D\u5305\u542B\u91DD\u5C0D\u53D7\u6B3A\u51CC\u8005\u7684\u5EFA\u8B70\u548C\u8CC7\u8A0A\uFF0C\u4EE5\u53CA\u6709\u7528\u7684\u7DB2\u7D61\u9023\u7D50\u548C\u5728\u7DDA\u8CC7\u6E90\u3002" })] });
var richText11 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Errol \u937E\u610F\u5712\u85DD\uFF0C\u5BB6\u88E1\u64FA\u6EFF\u6F02\u4EAE\u7684\u690D\u7269\uFF0C\u4F46\u4ED6\u5922\u60F3\u6709\u4E00\u500B\u771F\u6B63\u7684\u6236\u5916\u7A7A\u9593\u4F86\u683D\u7A2E\u66F4\u591A\u3002\u5728\u4ED6\u767C\u73FE\u4E00\u500B\u7A7A\u8569\u8569\u7684\u5C4B\u9802\u4F4D\u7F6E\u6642\uFF0C\u4ED6\u611F\u5230\u8208\u596E\u2014\u2014\u4F46\u4ED6\u5F88\u5FEB\u610F\u8B58\u5230\u4ED6\u4E0D\u80FD\u7368\u529B\u5B8C\u6210\u9019\u4E00\u5207\u3002\u5728\u9130\u5C45\u7684\u5E6B\u52A9\u4E0B\uFF0C\u4ED6\u5011\u628A\u5B83\u8B8A\u6210\u4E86\u4E00\u500B\u76DB\u958B\u7684\u82B1\u5712\uFF0C\u8B93\u5927\u5BB6\u805A\u5728\u4E00\u8D77\uFF0C\u5171\u540C\u5C55\u958B\u7F8E\u597D\u7684\u5192\u96AA\u3002" }), /* @__PURE__ */ e("p", { children: "\u9019\u500B\u6696\u5FC3\u7684\u96D9\u8A9E\u6545\u4E8B\u6176\u795D\u53CB\u60C5\u3001\u5718\u968A\u5408\u4F5C\u548C\u683D\u7A2E\u4E8B\u7269\u7684\u6A02\u8DA3\uFF0C\u4E26\u901A\u904E\u8272\u5F69\u7E7D\u7D1B\u7684\u63D2\u5716\u6355\u6349\u793E\u5340\u7CBE\u795E\u7684\u6A02\u8DA3\u3002\u975E\u5E38\u9069\u5408\u5E74\u8F15\u8B80\u8005\u548C\u5BB6\u5EAD\uFF0C\u4E5F\u662F\u5F15\u767C\u95DC\u65BC\u4E92\u76F8\u5E6B\u52A9\u548C\u767C\u73FE\u5C0F\u60F3\u6CD5\u5982\u4F55\u5728\u5404\u5730\u793E\u5340\u5275\u9020\u5927\u5FEB\u6A02\u7684\u7F8E\u597D\u9078\u64C7\u3002" })] });
var richText12 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u9047\u898B\u8FB2\u592B\u9D28\uFF0C\u4F62\u5514\u4FC2\u666E\u901A\u5605\u9D28\u5B50\u2014\u2014\u4F62\u55BA\u8FB2\u5834\u4E0A\u505A\u66EC\u8F9B\u82E6\u5605\u5DE5\u4F5C\uFF0C\u800C\u61F6\u60F0\u5605\u8FB2\u592B\u5C31\u55BA\u5E8A\u4E0A\u61F6\u6D0B\u6D0B\u54AC\u8457\u7CD6\u679C\u540C\u57CB\u7747\u5831\u7D19\u3002\u7531\u5288\u67F4\u3001\u7167\u9867\u6BCD\u96DE\u5230\u6D17\u7897\u540C\u57CB\u6458\u860B\u679C\uFF0C\u5462\u96BB\u53EF\u6190\u5605\u9D28\u5B50\u5FD9\u5230\u7B4B\u75B2\u529B\u7AED\uFF0C\u76F4\u5230\u4F62\u7D2F\u5012\u55BA\u5730\u4E0A\u3002\u6B63\u4FC2\u5462\u500B\u6642\u5019\uFF0C\u5176\u4ED6\u8FB2\u5834\u52D5\u7269\u9F4A\u5FC3\u5354\u529B\uFF0C\u7B56\u5283\u5497\u4E00\u500B\u5DE7\u5999\u5605\u8A08\u5283\uFF0C\u6559\u8FB2\u592B\u4E00\u500B\u6559\u8A13\uFF0C\u4EE4\u6BCF\u500B\u4EBA\u90FD\u516C\u5E73\u3002" }), /* @__PURE__ */ e("p", { children: "\u5462\u672C\u7D93\u5178\u96D9\u8A9E\u5716\u756B\u66F8\u4FC2\u8FB2\u5834\u88E1\u9762\u5605\u6700\u611B\uFF0C\u5145\u6EFF\u5497\u53EF\u611B\u89D2\u8272\u5605\u8FF7\u4EBA\u6C34\u5F69\u756B\uFF0C\u6545\u4E8B\u7C21\u55AE\u91CD\u8907\uFF0C\u6613\u65BC\u5C0F\u670B\u53CB\u53C3\u8207\u3002\u7121\u8AD6\u4FC2\u55BA\u5C4B\u4F01\u8212\u9069\u95B1\u8B80\uFF0C\u5B9A\u4FC2\u5B78\u6821\u88E1\u71B1\u9B27\u5605\u96C6\u9AD4\u6642\u9593\uFF0C\u90FD\u975E\u5E38\u9069\u5408\uFF0C\u8F15\u8F15\u5730\u5206\u4EAB\u5497\u6709\u95DC\u53CB\u8ABC\u3001\u52E4\u52DE\u540C\u4E92\u76F8\u652F\u6301\u5605\u601D\u60F3\uFF0C\u4EE5\u4E00\u7A2E\u6240\u6709\u5E74\u9F61\u90FD\u89BA\u5F97\u6709\u8DA3\u5605\u65B9\u5F0F\u3002" })] });
var richText13 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u4ECA\u65E5\u4FC2\u591A\u5143\u6587\u5316\u7F8E\u98DF\u65E5\uFF0C\u5572\u5C0F\u670B\u53CB\u5E36\u4F4F\u4F62\u54CB\u6587\u5316\u5605\u7F8E\u5473\u5C0F\u98DF\u569F\u5206\u4EAB\u2014\u60F3\u50CF\u4E00\u4E0B\u7A2E\u690D\u852C\u83DC\u3001\u8CFC\u8CB7\u98DF\u6750\u3001\u70F9\u8ABF\u7F8E\u98DF\uFF0C\u4EF2\u4E00\u9F4A\u4EAB\u7528\u3002\u5462\u500B\u6709\u97FB\u5F8B\u5605\u6545\u4E8B\u8DDF\u96A8\u8457\u5927\u5BB6\u5605\u5FEB\u6A02\uFF0C\u898B\u5230\u3001\u89F8\u6478\u3001\u805E\u5230\u3001\u54C1\u5690\u4F86\u81EA\u5168\u7403\u5605\u7F8E\u98DF\uFF0C\u751A\u81F3\u9F13\u52F5\u5572\u6311\u5254\u98DF\u5BA2\u8A66\u4E0B\u5572\u65B0\u5622\u3002\u5462\u500B\u6709\u8457\u6293\u8033\u65CB\u5F8B\u548C\u5FEB\u6A02\u5834\u666F\u5605\u6545\u4E8B\uFF0C\u4FC2\u4E00\u5834\u611F\u5B98\u76DB\u5BB4\uFF0C\u4EE4\u5C0F\u670B\u53CB\u5C0D\u5065\u5EB7\u98F2\u98DF\u548C\u5206\u4EAB\u5145\u6EFF\u8208\u596E\u3002" }), /* @__PURE__ */ e("p", { children: "\u7531Kate Clynes\u64B0\u5BEB\uFF0C\u5462\u672C\u8272\u5F69\u9BAE\u660E\u5605\u96D9\u8A9E\u66F8\u4EE5\u660E\u4EAE\u5605\u5716\u7247\u6829\u6829\u5982\u751F\uFF0C\u4E26\u5305\u62EC\u984D\u5916\u5605\u98DF\u8B5C\u548C\u6D3B\u52D5\uFF0C\u65B9\u4FBF\u55BA\u5C4B\u4F01\u6216\u8005\u73ED\u4E0A\u8A66\u5413\u3002\u5C0D\u65BC\u5BB6\u5EAD\u548C\u6559\u5E2B\u4F86\u8B1B\uFF0C\u5462\u500B\u4FC2\u4E00\u500B\u63A2\u7D22\u4E0D\u540C\u6587\u5316\u3001\u5F15\u767C\u95DC\u65BC\u5065\u5EB7\u98DF\u54C1\u5C0D\u8A71\u3001\u4EE5\u53CA\u900F\u904E\u6545\u4E8B\u548C\u5BE6\u8E10\u6D3B\u52D5\u5275\u9020\u7F8E\u597D\u56DE\u61B6\u5605\u7D55\u4F73\u65B9\u5F0F\u3002" })] });
var richText14 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u5728\u300A\u4F0A\u7D22\u5BD3\u8A00\u300B\u4E2D\u7684\u300A\u72D0\u72F8\u4E0E\u9E64\u300B\u4E2D\uFF0C\u4E00\u53EA\u8C03\u76AE\u7684\u72D0\u72F8\u7528\u4E00\u4E2A\u5E73\u76D8\u5B50\u4E0A\u83DC\uFF0C\u9E64\u65E0\u6CD5\u4ECE\u4E2D\u5403\u4E1C\u897F\uFF0C\u4F46\u4E0D\u4E45\u540E\u5F53\u9E64\u628A\u8FD9\u4E2A\u628A\u620F\u7FFB\u8F6C\u56DE\u6765\u65F6\uFF0C\u72D0\u72F8\u5438\u53D6\u4E86\u6559\u8BAD\u3002\u7136\u540E\uFF0C\u5728\u4E2D\u56FD\u6545\u4E8B\u300A\u68EE\u6797\u4E4B\u738B\u300B\u4E2D\uFF0C\u4E00\u53EA\u806A\u660E\u7684\u72D0\u72F8\u8FD0\u7528\u667A\u6167\u667A\u80DC\u5F3A\u5927\u7684\u8001\u864E\uFF0C\u8BC1\u660E\u667A\u6167\u603B\u662F\u80DC\u8FC7\u529B\u91CF\u2014\u2014\u5C31\u50CF\u5728\u300A\u683C\u9C81\u6CD5\u6D1B\u300B\u4E2D\u4E00\u6837\uFF01\u8FD9\u4E9B\u77ED\u6545\u4E8B\u6DF7\u5408\u4E86\u5DE7\u5999\u7684\u8F6C\u6298\u4E0E\u5173\u4E8E\u516C\u6B63\u548C\u806A\u660E\u601D\u8003\u7684\u6C38\u6052\u9053\u5FB7\u3002" }), /* @__PURE__ */ e("p", { children: "\u4F5C\u4E3AMantra Lingua\u7684\u5BD3\u8A00\u7CFB\u5217\u7684\u4E00\u90E8\u5206\uFF0C\u8FD9\u672C\u53CC\u8BED\u4E66\u5C06\u6765\u81EA\u4E0D\u540C\u6587\u5316\u7684\u5BD3\u8A00\u4E0E\u751F\u52A8\u7684\u63D2\u56FE\u642D\u914D\u5728\u4E00\u8D77\uFF0C\u4EE5\u5411\u5E74\u8F7B\u8BFB\u8005\u4ECB\u7ECD\u4E16\u754C\u6545\u4E8B\u548C\u5171\u540C\u7684\u6559\u8BAD\u3002\u9644\u6709\u6559\u5B66\u7B14\u8BB0\uFF0C\u975E\u5E38\u9002\u5408\u5BB6\u5EAD\u548C\u8BFE\u5802\u8BA8\u8BBA\u53CB\u5584\u3001\u5BF9\u4E0E\u9519\uFF0C\u4EE5\u53CA\u5982\u4F55\u901A\u8FC7\u6709\u8DA3\u7684\u8BA8\u8BBA\u548C\u6D3B\u52A8\u5C06\u6211\u4EEC\u6240\u6709\u4EBA\u8054\u7CFB\u5728\u4E00\u8D77\u3002" })] });
var richText15 = /* @__PURE__ */ r(n.Fragment, { children: [/* @__PURE__ */ e("p", { children: "\u55BA\u4E16\u754C\u5404\u5730\uFF0C\u6709\u597D\u591A\u540C\u4F60\u4E00\u6A23\u5605\u5C0F\u670B\u53CB\u90FD\u55BA\u4EAB\u53D7\u5404\u7A2E\u904A\u6232\u540C\u904B\u52D5\u2014\u2014\u55BA\u675C\u62DC\u540C Faris \u540C\u4F62\u7238\u7238\u8CFD\u99F1\u99DD\uFF0C\u55BA\u5370\u5EA6\u540C\u5168\u5BB6\u4E00\u9F4A\u6253\u677F\u7403\uFF0C\u6216\u8005\u55BA\u745E\u58EB\u6ED1\u96EA\uFF0C\u81EA\u7D30\u5DF2\u7D93\u597D\u4F3C Tomas \u5481\u3002\u4F60\u6700\u937E\u610F\u5605\u6236\u5916\u904A\u6232\u4FC2\u54A9\uFF1F\u5462\u672C\u958B\u5FC3\u5605\u66F8\u9080\u8ACB\u7D30\u8DEF\u4ED4\u53BB\u767C\u73FE\u4F86\u81EA\u5514\u540C\u5730\u65B9\u5605\u523A\u6FC0\u6D3B\u52D5\uFF0C\u540C\u6642\u5E7B\u60F3\u81EA\u5DF1\u4EA6\u53EF\u4EE5\u8A66\u5413\u3002" }), /* @__PURE__ */ e("p", { children: "\u4F5C\u70BA Mantra Lingua \u7684\u300A\u6211\u54CB\u7684\u751F\u6D3B\uFF0C\u6211\u54CB\u7684\u4E16\u754C\u300B\u7CFB\u5217\u4E4B\u4E00\uFF0C\u5462\u672C\u96D9\u8A9E\u66F8\u7528\u7C21\u55AE\u5605\u8A5E\u8A9E\u540C\u91CD\u8907\u6709\u8DA3\u5605\u5167\u5BB9\uFF0C\u5E6B\u52A9\u5C0F\u670B\u53CB\u4E86\u89E3\u591A\u5143\u6587\u5316\u540C\u751F\u6D3B\u65B9\u5F0F\uFF0C\u57F9\u990A\u4F62\u54CB\u5605\u5C0D\u8A71\u6280\u5DE7\u3002\u88E1\u9762\u5145\u6EFF\u5497\u95DC\u9375\u8A5E\u5F59\u540C\u6D3B\u52D5\uFF0C\u4FC2\u5BB6\u5EAD\u540C\u5B78\u6821\u4E00\u9F4A\u63A2\u7D22\u5605\u597D\u9078\u64C7\uFF0C\u555F\u767C\u6709\u95DC\u53CB\u8ABC\u3001\u50B3\u7D71\u540C\u5728\u4EFB\u4F55\u5730\u65B9\u73A9\u6A02\u7684\u8A0E\u8AD6\u3002" })] });
